/**
 * Analytics models for the dashboard API.
 */

/**
 * A single data point in a trend series.
 */
export interface TrendPoint {
  date: string;
  value: number;
}

/**
 * Per-user analytics breakdown.
 */
export interface UserAnalytics {
  userId: string;
  userName: string;
  orderCount: number;
  totalSpent: number;
  averageOrderValue: number;
}

/**
 * High-level analytics summary across all orders and users.
 */
export interface AnalyticsSummary {
  totalOrders: number;
  totalRevenue: number;
  averageOrderValue: number;
  ordersByStatus: Record<string, number>;
  totalUsers: number;
}

/**
 * Analytics service — aggregates data from orders and users for dashboard reporting.
 *
 * Depends on:
 * - OrderRepository (data layer) for order data
 * - UserRepository (data layer) for user data
 */

import type { AnalyticsSummary, UserAnalytics, TrendPoint } from '../models/analytics.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Get a high-level summary of all orders and users.
   */
  getSummary(): AnalyticsSummary {
    this.logger.info('Generating analytics summary');

    const orders = this.orderRepository.findAll();
    const users = this.userRepository.findAll();

    const totalOrders = orders.length;
    const totalRevenue = orders.reduce((sum, order) => sum + order.total, 0);
    const averageOrderValue = totalOrders > 0 ? totalRevenue / totalOrders : 0;

    const ordersByStatus: Record<string, number> = {};
    for (const order of orders) {
      ordersByStatus[order.status] = (ordersByStatus[order.status] ?? 0) + 1;
    }

    return {
      totalOrders,
      totalRevenue,
      averageOrderValue,
      ordersByStatus,
      totalUsers: users.length,
    };
  }

  /**
   * Get analytics for a specific user.
   */
  getUserAnalytics(userId: string): UserAnalytics {
    this.logger.info(`Generating analytics for user: ${userId}`);

    const user = this.userRepository.findById(userId);
    if (!user) {
      throw new Error(`User not found: ${userId}`);
    }

    const orders = this.orderRepository.findByUserId(userId);
    const orderCount = orders.length;
    const totalSpent = orders.reduce((sum, order) => sum + order.total, 0);
    const averageOrderValue = orderCount > 0 ? totalSpent / orderCount : 0;

    return {
      userId: user.id,
      userName: user.name,
      orderCount,
      totalSpent,
      averageOrderValue,
    };
  }

  /**
   * Get order trends grouped by date.
   * Returns a TrendPoint for each date that has orders, sorted chronologically.
   */
  getTrends(): TrendPoint[] {
    this.logger.info('Generating order trends');

    const orders = this.orderRepository.findAll();

    const revenueByDate = new Map<string, number>();
    for (const order of orders) {
      const date = order.createdAt.toISOString().split('T')[0]!;
      revenueByDate.set(date, (revenueByDate.get(date) ?? 0) + order.total);
    }

    const trends: TrendPoint[] = Array.from(revenueByDate.entries()).map(
      ([date, value]) => ({ date, value }),
    );

    trends.sort((a, b) => a.date.localeCompare(b.date));

    return trends;
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { User } from '../../src/models/user.js';
import type { Order } from '../../src/models/order.js';

describe('AnalyticsService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let orderRepo: OrderRepository;
  let service: AnalyticsService;

  const now = new Date('2026-01-15T10:00:00Z');
  const yesterday = new Date('2026-01-14T10:00:00Z');

  function createUser(overrides: Partial<User> = {}): User {
    const user: User = {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: now,
      updatedAt: now,
      ...overrides,
    };
    userRepo.save(user);
    return user;
  }

  function createOrder(overrides: Partial<Order> = {}): Order {
    const order: Order = {
      id: `order-${Math.random().toString(36).slice(2, 6)}`,
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      total: 10,
      status: 'pending',
      createdAt: now,
      updatedAt: now,
      ...overrides,
    };
    orderRepo.save(order);
    return order;
  }

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
  });

  describe('getSummary', () => {
    it('should return zeros when no data exists', () => {
      const summary = service.getSummary();

      expect(summary.totalOrders).toBe(0);
      expect(summary.totalRevenue).toBe(0);
      expect(summary.averageOrderValue).toBe(0);
      expect(summary.ordersByStatus).toEqual({});
      expect(summary.totalUsers).toBe(0);
    });

    it('should summarize orders and users', () => {
      createUser();
      createUser({ id: 'user-2', name: 'Bob', email: 'bob@example.com' });
      createOrder({ id: 'order-1', total: 30, status: 'pending' });
      createOrder({ id: 'order-2', total: 20, status: 'confirmed' });
      createOrder({ id: 'order-3', total: 50, status: 'pending' });

      const summary = service.getSummary();

      expect(summary.totalOrders).toBe(3);
      expect(summary.totalRevenue).toBe(100);
      expect(summary.averageOrderValue).toBeCloseTo(33.33, 1);
      expect(summary.ordersByStatus).toEqual({ pending: 2, confirmed: 1 });
      expect(summary.totalUsers).toBe(2);
    });
  });

  describe('getUserAnalytics', () => {
    it('should throw for non-existent user', () => {
      expect(() => service.getUserAnalytics('nonexistent')).toThrow(
        'User not found',
      );
    });

    it('should return analytics for user with no orders', () => {
      createUser();

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.userId).toBe('user-1');
      expect(analytics.userName).toBe('Alice');
      expect(analytics.orderCount).toBe(0);
      expect(analytics.totalSpent).toBe(0);
      expect(analytics.averageOrderValue).toBe(0);
    });

    it('should return analytics for user with orders', () => {
      createUser();
      createOrder({ id: 'order-1', userId: 'user-1', total: 30 });
      createOrder({ id: 'order-2', userId: 'user-1', total: 20 });

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.orderCount).toBe(2);
      expect(analytics.totalSpent).toBe(50);
      expect(analytics.averageOrderValue).toBe(25);
    });

    it('should only include orders for the specified user', () => {
      createUser();
      createUser({ id: 'user-2', name: 'Bob', email: 'bob@example.com' });
      createOrder({ id: 'order-1', userId: 'user-1', total: 30 });
      createOrder({ id: 'order-2', userId: 'user-2', total: 100 });

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.orderCount).toBe(1);
      expect(analytics.totalSpent).toBe(30);
    });
  });

  describe('getTrends', () => {
    it('should return empty array when no orders exist', () => {
      const trends = service.getTrends();
      expect(trends).toEqual([]);
    });

    it('should group revenue by date', () => {
      createUser();
      createOrder({ id: 'order-1', total: 30, createdAt: now });
      createOrder({ id: 'order-2', total: 20, createdAt: now });
      createOrder({ id: 'order-3', total: 50, createdAt: yesterday });

      const trends = service.getTrends();

      expect(trends).toHaveLength(2);
      expect(trends[0]).toEqual({ date: '2026-01-14', value: 50 });
      expect(trends[1]).toEqual({ date: '2026-01-15', value: 50 });
    });

    it('should sort trends chronologically', () => {
      createUser();
      createOrder({ id: 'order-1', total: 10, createdAt: now });
      createOrder({ id: 'order-2', total: 20, createdAt: yesterday });

      const trends = service.getTrends();

      expect(trends[0]!.date).toBe('2026-01-14');
      expect(trends[1]!.date).toBe('2026-01-15');
    });
  });
});

